using System.ComponentModel;
using System.Text.RegularExpressions;

/// <summary>
/// In-memory notebook that the agent uses to record and review research findings.
/// </summary>
public sealed partial class Notebook
{
    private readonly Dictionary<string, string> _notes = new();

    [Description("Saves a research finding with a title and content.")]
    public string Save(
        [Description("Short descriptive title for the note")] string title,
        [Description("The finding or information to record")] string content)
    {
        _notes[title] = content;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetAll()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((kv, i) =>
            $"[{i + 1}] {kv.Key}\n{kv.Value}"));
    }
}

/// <summary>
/// Searches the web using DuckDuckGo Lite (no API key required).
/// </summary>
public sealed partial class WebSearcher(HttpClient httpClient)
{
    [Description("Searches the web for information about a query and returns text snippets from the results.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔎 Searching: \"{query}\"");
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept-Language", "en-US,en;q=0.9");

            var response = await httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();
            var text = StripHtml(html);

            // Return a useful window of content for the model
            const int maxLength = 3000;
            return text.Length > maxLength ? text[..maxLength] : text;
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks entirely
        var cleaned = ScriptStyleRegex().Replace(html, " ");
        // Remove HTML tags
        cleaned = TagRegex().Replace(cleaned, " ");
        // Decode common HTML entities
        cleaned = cleaned
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");
        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ");
        return cleaned.Trim();
    }

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();
}

