using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the chat client through the MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Instantiate tools ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var notebook = new Notebook();
var searcher = new WebSearcher(httpClient);

var tools = new AITool[]
{
    AIFunctionFactory.Create(searcher.SearchAsync, name: "SearchWeb"),
    AIFunctionFactory.Create(notebook.Save, name: "SaveNote"),
    AIFunctionFactory.Create(notebook.GetAll, name: "GetNotes"),
};

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. Given a topic:
        1. Use SearchWeb to find information from multiple angles (at least 3 varied searches).
        2. Use SaveNote to record each key finding with a descriptive title.
        3. After gathering enough information, use GetNotes to review what you collected.
        4. Write a well-structured summary covering key points, different perspectives,
           and notable details.
        Be methodical: search broadly first, then dive deeper into interesting sub-topics.
        """,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking.",
    tools: tools);

// --- Get the research topic from the user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent with guardrails ---
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var session = new ChatClientAgentSession();

var response = await agent.RunAsync(
    $"Research this topic thoroughly and provide a comprehensive summary: {topic}",
    session,
    runOptions);

// --- Display the final summary ---
Console.WriteLine();
Console.WriteLine("═══════════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════");
Console.WriteLine();
Console.WriteLine(response.Message.Text);

